      "planet_mass": "Pek pa planet",
      "tidal_forces_gradually_slow_a_moon_s_r": "Teko me kwot dwoko wir pa dwe mot mot nio ka orwate ki kare mere me wir. Dwe megwa gimake matek (tidally locked): tuŋ acel-lu kare ducu i kom Lobo. Mercury tye i resonance me 3:2 ki Ceŋ (pe gimake liweŋ).",
      "crater_counter": "🌑 Lakwan Bur",
      "click_each_crater_real_planetary_scien": "Dii bur acel acel. Lupwony ada me planet kwano bur me ŋeyo dit pa mwaka pa wi ngom — bur mapol = teggi loyo.",
      "click_craters_to_count_them": "🔍 Dii bur wek ikwan gin",
      "reset_3": "Dwok cen",
      "crater_counting_is_how_scientists_dete": "Kwano bur aye yo ma lupwony giŋeyo kwede mwaka pa wi ngom pa planet. Bur mapol = wi ngom ma teggi. Got pa Dwe tye ki bur mapol (teggi twatwal); maria gin lava manyen.",
      "gravity_well_visualizer": "⚖ Lanyut me Bur pa Gravity",
      "mass_curves_spacetime_drag_mass_watch_": "Pek kuko spacetime. Ywai pek + nen kit ma bur tut kwede. Wir apwol wek inen kit ma poto iye kwede.",
      "mass_2": "Pek",
      "ball_position": "Ka ma apwol tye iye",
      "einstein_s_general_relativity_says_mas": "General relativity pa Einstein waco ni pek kuko spacetime. Jami pe winyo teko mo — gin lubo geodesic i kom kit ma okuk. Man aye gravity. Black hole kuko spacetime matek twatwal ma kadi ryeny pe twero a woko.",
      "asteroid_composition": "🪨 Jami ma Cweyo Asteroid",
      "three_main_asteroid_types_c_s_m_mining": "Kit me asteroid adek madongo: C, S, M. Kampany me kunyo yenyo mega me M pi nyonyo + platinum.",
      "c_type_carbonaceous": "Kit me C (Carbonaceous)",
      "most_common_75_dark_primitive_water_ri": "Pol loyo (75%). Macol, macon, opoŋ ki pii. Ginoŋogi i kor ma woko.",
      "s_type_silicaceous": "Kit me S (Silicaceous)",
      "stony_17_lighter_made_of_silicate_mine": "Me kidi (17%). Yot loyo, gicweyo ki silicate + nyonyo. Ginoŋogi i kor ma iye.",
      "m_type_metallic": "Kit me M (Metallic)",
      "metal_rich_8_mostly_iron_nickel_possib": "Opoŋ ki nyonyo (8%). Dwoŋ mere nyonyo + nickel. Gwok a ki i cwiny pa protoplanet ma otur. Ka ma kunyo mito.",
      "cosmic_microwave_background": "📡 Cosmic Microwave Background",
      "light_from_380_000_years_after_the_big": "Ryeny ma a ki i mwaka 380,000 i ŋe Big Bang. Apoka-poka matino aye nyig pa galaxy ducu.",
      "cosmic_microwave_background_simulated": "Cosmic Microwave Background (ma gicweyo)",
      "temperature_fluctuations_of_0_0001_see": "Apoka-poka me lyeto ma cok 0.001% — nyig pa jami ducu",
      "contrast": "Contrast",
      "the_cmb_is_leftover_light_from_380_000": "CMB obedo ryeny ma odoŋ ki i mwaka 380,000 i ŋe Big Bang. Apoka-poka matino me lyeto nyuto ka ma jami onoŋo tek manok iye. Kabedo ma tek magi aye odongo odoko galaxy + lakalatwe ducu ma waneno tin. Penzias + Wilson gunoŋo pa kore i 1965 (Nobel Prize 1978).",
      "saturn_ring_composer": "🪐 Layub me Piny pa Saturn",
      "saturn_s_rings_are_99_water_ice_in_tri": "Piny pa Saturn obedo 99% pee me pii i nucu trilion mapol. Gwok gitye ki milion mwaka 100 keken.",
      "saturn_s_rings": "Piny pa Saturn",
      "ice_fraction": "Nucu pa pee",
      "ring_density": "Dwoŋ pa piny",
      "saturn_s_rings_are_mostly_water_ice_pa": "Piny pa Saturn dwoŋ mere obedo nyig pee me pii ma cakke ki buru o i nyig ma rom ki ot. Lac mere km 282,000 ento dwoŋ mere pe romo km 1. Gwok ocweyo ki dwe ma otur i milion mwaka ~100 mukato — nyen mada!",
      "custom_planet_builder": "🪐 Lagedo Planet mameri",
      "pick_a_core_surface_atmosphere_and_lif": "Yer cwiny, wi ngom, yamo, ki kwo. Nen kit me lobo ma iyubo.",
      "your_world": "Lobo Meri",
      "add_life": "Med kwo",
      "pulsar_beam_sweeper": "📡 Lanyut me Ryeny pa Pulsar",
      "pulsars_are_spinning_neutron_stars_wit": "Pulsar gin neutron star ma wiro ma tye ki ryeny me magnet. Lobo neno mil keken ka ryeny okato.",
